output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?player ?playerLabel WHERE {
  {
    wd:Q362360 rdfs:label ?playerLabel .
    BIND(wd:Q362360 AS ?player)
    FILTER(LANG(?playerLabel) = "en")
  } UNION {
    ?player wdt:P31 wd:Q5 ; wdt:P106 wd:Q2311450 ; rdfs:label ?playerLabel .
    FILTER(LANG(?playerLabel) = "en")
    FILTER CONTAINS(?playerLabel , "Norm")
  }
}
LIMIT 1

args.sparql:
SELECT ?player ?playerLabel WHERE { {
  wd:Q362360 rdfs:label ?playerLabel .
  BIND(wd:Q362360 AS ?player)
  FILTER(LANG(?playerLabel) = "en")
}
UNION
{
  # Alternative approach if direct entity link fails
  ?player wdt:P31 wd:Q5 ;
          wdt:P106 wd:Q2311450 ;
          rdfs:label ?playerLabel .
  FILTER(LANG(?playerLabel) = "en")
  FILTER CONTAINS(?playerLabel, "Norm")
}
}
LIMIT 1
